<template>
    <div class="task">
        <div class="task__wrapper container">
            <div class="task__header">
                <div class="task__close" @click="$emit('closeModalTask')"></div>
                <div class="task__params">
                    <div
                            class="task__param"
                            v-if="!edit && !favorites"
                            @click="editTask"
                            :style="{backgroundImage:'url(' + require('@/assets/icons/edit.svg') + ')',}"
                    ></div>
                    <div
                            class="task__param"
                            v-if="edit && !favorites"
                            @click="editTask"
                            :style="{backgroundImage:'url(' + require('@/assets/icons/check.svg') + ')',}"
                    ></div>
                    <div
                            class="task__param"
                            @click="toggleFavorite"
                            v-if="!addedFavorites && $route.path != '/favorites'"
                            :style="{backgroundImage:'url(' + require('@/assets/icons/favorites.svg') + ')',}"
                    ></div>
                    <div
                            class="task__param"
                            @click="toggleFavorite"
                            v-else-if="addedFavorites && $route.path != '/favorites'"
                            :style="{backgroundImage:'url(' + require('@/assets/icons/favorites-acive.svg') + ')',}"
                    ></div>
                    <div
                            class="task__param"
                            @click="$emit('removeTask', taskIndex)"
                            :style="{
              backgroundImage:
                'url(' + require('@/assets/icons/remove.svg') + ')',
            }"
                    ></div>
                </div>
            </div>
            <div
                    class="task__date"
                    v-if="tasks[taskIndex].deadline"
            >
                {{ `${
                new Date(tasks[taskIndex].deadline).getDate() < 10 ? '0' + new Date(tasks[taskIndex].deadline).getDate()
                : new
                Date(tasks[taskIndex].deadline).getDate()
                }-${
                new Date(tasks[taskIndex].deadline).getMonth() < 10 ? '0' + Number(1 + new
                Date(tasks[taskIndex].deadline).getMonth()) :
                Number(1 + new Date(tasks[taskIndex].deadline).getMonth())
                }-${
                new Date(tasks[taskIndex].deadline).getFullYear()
                } ${
                new Date(tasks[taskIndex].deadline).getHours() < 10 ? '0' + new
                Date(tasks[taskIndex].deadline).getHours() : new
                Date(tasks[taskIndex].deadline).getHours()
                } : ${
                new Date(tasks[taskIndex].deadline).getMinutes() < 10 ? '0' + new
                Date(tasks[taskIndex].deadline).getMinutes() : new
                Date(tasks[taskIndex].deadline).getMinutes()
                }` }}
            </div>
            <h2 class="task__title" v-if="!edit"
                :class="{ 'text-completed': tasks[taskIndex].subtasks.every(elem => elem.completed == true) }">
                {{ tasks[taskIndex].title }}</h2>
            <input class="task__title-inp" type="text" v-model="tasks[taskIndex].title" v-if="edit">

            <ul class="task__subtasks">
                <li
                        class="task__subtask"
                        v-for="(subTask, index) in tasks[taskIndex].subtasks"
                        :key="'sub' + index"
                >
                    <input
                            type="checkbox"
                            @click="completedSubTask(index)"
                            v-if="!edit"
                            class="task__subtask-checkbox"
                            v-model="
              tasks[taskIndex].subtasks[index].completed ? 'checked' : ''
            "
                            :id="taskIndex + index"
                    />
                    <label
                            :for="taskIndex + index"
                            v-if="!edit"
                            :class="{
              'text-completed':
                tasks[taskIndex].subtasks[index].completed,
            }"
                    >{{ subTask.title }}</label
                    >
                    <input class="task__subtask-inp" v-model="tasks[taskIndex].subtasks[index].title" type="text"
                           v-if="edit">
                    <button class="task__subtask-remove" v-if="edit" @click="removeSubTask(index)"></button>
                </li>

            </ul>
            <button class="task__add-subtask" v-if="edit" @click="addSubTask">Добавить подзадачу</button>
        </div>
    </div>
</template>

<script>
    export default {
        props: {
            taskIndex: Number,
            allTasks: [],
            favorites: Boolean,
        },
        data() {
            return {
                tasks: [],
                addedFavorites: false,
                edit: false,
            };
        },
        computed: {
            allFavorites() {
                return this.$store.getters.favorites;
            },
        },
        mounted() {
            this.tasks = this.allTasks;
            if (this.allFavorites.find(item => item.idTask == this.tasks[this.taskIndex].idTask)) {
                this.addedFavorites = true;
            }
            console.log(this.$route.path)
        },
        methods: {
            completedSubTask(index) {
                this.tasks[this.taskIndex].subtasks[index].completed =
                    !this.tasks[this.taskIndex].subtasks[index].completed;
                this.$emit('saveTasks', this.tasks)
            },
            toggleFavorite() {
                if (!this.allFavorites.find(item => item.idTask == this.tasks[this.taskIndex].idTask)) {
                    this.$emit('addFavorites', this.taskIndex)
                    this.addedFavorites = true;
                } else {
                    this.$emit('removeFavorites', this.taskIndex)
                    this.addedFavorites = false;
                }
            },
            editTask() {
                if (this.edit) {
                    this.$store.commit("addTasks", this.tasks);
                    localStorage.setItem("tasks", JSON.stringify(this.tasks));
                    if (this.allFavorites.find(item => item.idTask == this.tasks[this.taskIndex].idTask)) {
                        const favoriteIndex = this.allFavorites.findIndex(item => item.idTask == this.tasks[this.taskIndex].idTask)
                        this.allFavorites[favoriteIndex] = this.tasks[this.taskIndex]

                        this.$store.commit("addFavorites", this.allFavorites);
                        localStorage.setItem("favorites", JSON.stringify(this.allFavorites));
                    }
                }
                this.edit = !this.edit;
            },
            removeSubTask(index) {
                this.tasks[this.taskIndex].subtasks.splice(index, 1)
            },
            addSubTask() {
                this.tasks[this.taskIndex].subtasks.push({
                    completed: false,
                    title: "",
                });
            }
        },
    };
</script>

<style lang="scss" scoped>
    $blue: #1771f1;
    $blue-hover: #095ed6;
    $dark: #131313;

    .task {
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background-color: #030303;
        color: #fff;
        z-index: 100;
        overflow: scroll;
        padding-bottom: 20px;

        &::-webkit-scrollbar {
            width: 0;
        }

        .task__wrapper {
            height: 100%;
            min-height: 500px;
        }

        .task__header {
            width: 100%;
            height: 50px;
            display: flex;
            justify-content: space-between;
            align-items: center;

            .task__close {
                width: 17px;
                height: 17px;
                background-image: url(../assets/icons/left-arrow.svg);
                background-size: 100%;
                background-position: center;
                background-repeat: no-repeat;
            }

            .task__params {
                display: flex;
                align-items: center;

                .task__param {
                    width: 20px;
                    height: 20px;
                    background-size: 100%;
                    background-position: center;
                    background-repeat: no-repeat;

                    &:not(:last-child) {
                        margin-right: 13px;
                    }
                }
            }
        }

        .task__date {
            margin-top: 13px;
            font-size: 11px;
        }

        .task__title {
            margin-top: 5px;
            font-size: 23px;
        }

        .task__title-inp {
            width: 100%;
            height: 45px;
            margin-top: 10px;
            border-radius: 8px;
        }

        .task__subtasks {
            margin-top: 15px;
            list-style: none;

            .task__subtask {
                display: flex;

                &:not(:first-child) {
                    margin-top: 10px;
                }

                label {
                    margin-left: 10px;
                    font-size: 16px;
                }

                .task__subtask-inp {
                    width: 100%;
                    height: 30px;
                    border-radius: 8px;
                }

                .task__subtask-remove {
                    padding: 0 15px;
                    height: 30px;
                    margin-left: 5px;
                    border-radius: 8px;
                    background-color: $dark;
                    background-image: url("../assets/icons/close.svg");
                    background-repeat: no-repeat;
                    background-size: 35%;
                    background-position: center;
                }
            }
        }

        .task__add-subtask {
            width: 100%;
            height: 40px;
            margin-top: 15px;
        }
    }
</style>