<template>
  <div class="favorites">
    <transition name="fade">
      <Task
          v-if="modalTask"
          :allTasks="allFavorites"
          :taskIndex="taskIndex"
          :favorites="true"

          @saveTasks="saveTasks"
          @closeModalTask="closeModalTask"
          @removeTask="removeTask"
      />
    </transition>
    <div class="favorites__content container">

      <div class="tasks">
        <Search
            @searchTasks="searchTasks"
        />
        <div class="tasks__row-title-btn">
          <h2 class="tasks__title" v-if="allFavorites.length">Задачи</h2>
          <div
              class="tasks__toggle-tasks"
              v-if="allFavorites.length"
              :class="{ 'tasks__toggle-tasks_col': column }"
              @click="columnBlock"
          ></div>
        </div>
        <h2 class="tasks__empty" v-if="!allFavorites.length">Здесь пока пусто</h2>
        <Tasks v-if="allFavorites.length" @openTask="openTask" :allTasks="allFavorites" :column="column" :searchValue="searchValue"/>
      </div>

    </div>
    <Nav/>
  </div>
</template>

<script>
import Nav from "@/components/Nav.vue";
import Search from "@/components/Search.vue";
import Tasks from "@/components/Tasks.vue";
import Task from "@/components/Task.vue";

export default {
  components: {
    Nav,
    Tasks,
    Search,
    Task,
  },
  data() {
    return {
      allFavorites: [],
      searchValue: "",
      modalTask: false,
      taskIndex: Number,
      column: false,
    }
  },
  computed: {
    favorites() {
      return this.$store.getters.favorites;
    },
  },
  created: function () {
    if (localStorage.favorites) {
      this.$store.commit("addFavorites", JSON.parse(localStorage.getItem("favorites")));
      this.allFavorites = this.favorites;
    }
  },
  mounted() {
    if(localStorage.getItem('column') == 'true') {
      this.column = true
    }
  },
  methods: {
    openTask(index) {
      this.taskIndex = index;
      this.modalTask = true;
    },
    saveTasks(tasks) {
      localStorage.setItem("favorites", JSON.stringify(tasks));
    },
    closeModalTask() {
      this.modalTask = false;
    },
    removeTask(index) {
      console.log(index);
      this.allFavorites.splice(index, 1);
      this.$store.commit("addFavorites", this.allFavorites);
      localStorage.setItem("favorites", JSON.stringify(this.allFavorites));
      this.closeModalTask();
    },
    searchTasks(value) {
      this.searchValue = value;
      console.log(value)
    },
    columnBlock() {
      this.column = !this.column
      localStorage.column = JSON.stringify(this.column);
    }
  }
};
</script>

<style lang="scss">
.favorites__content {
  .tasks {
    padding-top: 15px;
  }
}
</style>