import Vue from "vue";
import Vuex from "vuex";

Vue.use(Vuex);

export default new Vuex.Store({
    state: {
        apiUrl: 'https://a2213-db34.f.d-f.pw',
        tasks: [],
        favorites: [],
        token: '',
    },
    getters: {
        tasks(state) {
            return state.tasks;
        },
        favorites(state) {
            return state.favorites;
        },
        apiUrl(state) {
            return state.apiUrl
        },
        token(state) {
            return state.token
        }
    },
    mutations: {
        addTasks(state, tasks) {
            state.tasks = tasks;
        },
        addFavorites(state, tasks) {
            state.favorites = tasks;
        },
        signIn(state, token) {
            state.token = token;
        },
    },
    actions: {}
});
