<template>
  <div class="profile">
    <div class="container">
      <div class="profile__avatar-wrapper">
        <div class="profile__param"></div>
        <div class="profile__avatar" v-if="userInfo.profileImage"
             :style="{ backgroundImage: `url(${apiUrl}${userInfo.profileImage})` }">
          <input type="file" class="profile__upload-avatar" @change="uploadAavatar">
        </div>
        <div class="profile__no-avatar" v-if="!userInfo.profileImage">
          <p>{{ userInfo.username[0].toUpperCase() }}</p>
          <input type="file" class="profile__upload-avatar" @change="uploadAavatar">
        </div>
        <div class="profile__param" @click="signOut">
          <img src="@/assets/icons/signOut.svg" alt="signOut">
        </div>
      </div>


      <div class="profile__title">{{ userInfo.username }}</div>

      <ul class="profile__links">
        <router-link to="/" tag="li" class="profile__link">
          <p>Настройки</p>
          <img src="@/assets/icons/arrow.svg" alt="arrow">
        </router-link>
        <router-link to="/" tag="li" class="profile__link">
          <p>О приложении</p>
          <img src="@/assets/icons/arrow.svg" alt="arrow">
        </router-link>
        <router-link to="/" tag="li" class="profile__link">
          <p>Обратная связь</p>
          <img src="@/assets/icons/arrow.svg" alt="arrow">
        </router-link>
      </ul>
    </div>
    <Nav/>
  </div>
</template>

<script>
import Nav from "@/components/Nav.vue";

export default {
  components: {
    Nav,
  },
  data() {
    return {
      authorized: false,
      userInfo: [],
    }
  },
  computed: {
    token() {
      return this.$store.getters.token;
    },
    apiUrl() {
      return this.$store.getters.apiUrl;
    }
  },
  mounted() {
    if (!this.token.length) {
      this.$router.push('/sign-in')
    }
    if (this.token.length) {
      fetch(`${this.apiUrl}/api/account`, {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${this.token}`
        }
      })
          .then((response) => response.json())
          .then((data) => {
            console.log(data)
            this.userInfo = data;
          })
    }
  },
  methods: {
    signOut() {
      this.$store.commit('signIn', '');
      localStorage.removeItem('token');
      this.$router.push('/');
    },
    uploadAavatar(e) {
      const file = e.target.files;
      const formData = new FormData();
      formData.append('files', file[0]);
      const response = fetch(`${this.apiUrl}/api/account/upload-image`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${this.token}`,
        },
        body: formData,
      })
          .then(() => {
            fetch(`${this.apiUrl}/api/account`, {
              method: 'GET',
              headers: {
                'Authorization': `Bearer ${this.token}`
              }
            })
                .then((response) => response.json())
                .then((data) => {
                  console.log(data)
                  this.userInfo = data;
                })
          })
    }
  }
};
</script>

<style lang="scss">
$blue: #1771f1;
$blue-hover: #095ed6;
$dark: #131313;

.profile {
  .profile__avatar-wrapper {
    max-width: 260px;
    height: 100px;
    margin-left: auto;
    margin-right: auto;
    margin-top: 30px;
    display: flex;
    align-items: center;
    justify-content: space-between;
  }

  .profile__avatar {
    position: relative;
    width: 100px;
    height: 100px;
    border-radius: 100%;
    margin-left: auto;
    margin-right: auto;
    background-color: $dark;
    background-size: cover;
    background-repeat: no-repeat;
    background-position: center;

    input {
      position: absolute;
      top: 0;
      left: 0;
      width: 100px;
      height: 100px;
      border-radius: 100%;
      opacity: 0;
    }
  }

  .profile__no-avatar {
    position: relative;
    width: 100px;
    height: 100px;
    border-radius: 100%;
    margin-left: auto;
    margin-right: auto;
    display: flex;
    align-items: center;
    justify-content: center;
    background-color: $dark;
    color: $blue;

    p {
      font-size: 40px;
      font-weight: 600;
    }

    input {
      position: absolute;
      top: 0;
      left: 0;
      width: 100px;
      height: 100px;
      border-radius: 100%;
      opacity: 0;
    }
  }

  .profile__param {
    width: 50px;
    height: 50px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 100%;
    background-color: $dark;

    &:first-child {
      background-color: transparent;
    }

    img {
      min-width: 15px;
      max-width: 15px;
    }
  }

  .profile__title {
    margin-top: 20px;
    text-align: center;
    font-size: 30px;
    font-weight: 600;
  }

  .profile__links {
    margin-top: 30px;
    list-style: none;

    .profile__link {
      width: 100%;
      height: 45px;
      padding: 0 15px;
      border-radius: 10px;
      background-color: $dark;
      display: flex;
      align-items: center;
      justify-content: space-between;

      &:not(:first-child) {
        margin-top: 5px;
      }

      p {
        font-size: 15px;
      }

      img {
        max-width: 13px;
      }
    }
  }
}
</style>