<template>
    <div class="tasks-wrapper" :class="{ 'tasks-wrapper_col': column }">
        <div
                class="tasks-wrapper__task"
                v-for="(task, index) in tasks"
                :class="{
                    'wrapper__task-expired':
                      new Date(task.deadline).valueOf() < dateNow,

                    'tasks-wrapper__task-start': task.subtasks.some(
                      (elem) => elem.completed == true
                    ),

                    'tasks-wrapper__task-completed': task.subtasks.every(
                      (elem) => elem.completed == true
                    ),
                 }"
                :key="'task' + index"
                @click="$emit('openTask', index)"
        >
            <p
                    class="tasks-wrapper__date"
                    v-if="task.deadline"
            >
                {{ `${
                new Date(task.deadline).getDate() < 10 ? '0' + new Date(task.deadline).getDate() : new
                Date(task.deadline).getDate()
                }-${
                new Date(task.deadline).getMonth() < 10 ? '0' + Number(1 + new Date(task.deadline).getMonth()) :
                Number(1 + new Date(task.deadline).getMonth())
                }-${
                new Date(task.deadline).getFullYear()
                } ${
                new Date(task.deadline).getHours() < 10 ? '0' + new Date(task.deadline).getHours() : new
                Date(task.deadline).getHours()
                } : ${
                new Date(task.deadline).getMinutes() < 10 ? '0' + new Date(task.deadline).getMinutes() : new
                Date(task.deadline).getMinutes()
                }` }}
            </p>
            <h3
                    class="tasks-wrapper__title"
                    :class="{
          'text-completed': task.subtasks.every(
            (elem) => elem.completed == true
          ),
        }"
            >
                {{ task.title }}
            </h3>

            <ul class="tasks-wrapper__subtasks">
                <li
                        class="tasks-wrapper__subtask"
                        v-for="(subTask, index) in task.subtasks"
                        :class="{ 'text-completed': subTask.completed }"
                        :key="'subTask' + index"
                >
                    {{ subTask.title }}
                </li>
            </ul>
        </div>
    </div>
</template>

<script>
    export default {
        props: {
            column: Boolean,
            searchValue: String,
            allTasks: [],
        },
        data() {
            return {
                tasks: [],
                date: '',
                dateNow: Date.now(),
            };
        },
        watch: {
            searchValue: function () {
                console.log(this.searchValue);

                const taksElem = document.querySelectorAll(".tasks-wrapper__task");
                this.tasks.forEach((item, index) => {
                    if (
                        item.title.toUpperCase().indexOf(this.searchValue.toUpperCase()) > -1
                    ) {
                        taksElem[index].style.display = "";
                    } else {
                        taksElem[index].style.display = "none";
                    }
                });
            },
        },
        mounted() {
            this.tasks = this.allTasks;
            console.log(this.allTasks)
            const date = new Date();
            const fullDate = `${date.getFullYear()}-${
                date.getMonth() > 10 ? date.getMonth() : "0" + date.getMonth()
            }-${date.getDate() > 10 ? date.getDate() : "0" + date.getDate()}`;

            this.countingDate()
        },
        methods: {
            countingDate() {
                setInterval(() => {
                    this.dateNow = Date.now()
                }, 2000)
            }
        }
    };
</script>

<style lang="scss" scoped>
    $blue: #1771f1;
    $blue-hover: #095ed6;
    $dark: #131313;

    .tasks-wrapper {
        width: 100%;
        margin-top: 10px;
        margin-left: -2%;
        display: flex;
        flex-wrap: wrap;

        .tasks-wrapper__task {
            position: relative;
            width: 48%;
            min-height: 140px;
            max-height: 140px;
            margin-left: 2%;
            border-radius: 13px;
            padding-left: 15px;
            padding-right: 10px;
            padding-top: 13px;
            overflow: hidden;
            background-color: $dark;
            margin-top: 2%;
            cursor: pointer;

            &::before {
                content: "";
                position: absolute;
                bottom: 0;
                left: 0;
                width: 100%;
                height: 70%;
                -webkit-box-shadow: 0px -100px 43px -33px rgba(19, 19, 19, 1) inset;
                -moz-box-shadow: 0px -100px 43px -33px rgba(19, 19, 19, 1) inset;
                box-shadow: 0px -100px 43px -33px rgba(19, 19, 19, 1) inset;
                z-index: 2;
            }

            .tasks-wrapper__date {
                margin-top: 0px;
                font-size: 11px;
            }

            .tasks-wrapper__title {
                margin-top: 7px;
                font-size: 16px;
            }

            .tasks-wrapper__subtasks {
                margin-top: 5px;
                max-height: 80px;
                overflow: hidden;
                list-style: none;

                .tasks-wrapper__subtask {
                    font-size: 13px;
                }
            }
        }

        .tasks-wrapper__task-start {
            background-color: #4d97ff;

            &::before {
                content: "";
                position: absolute;
                bottom: 0;
                left: 0;
                width: 100%;
                height: 70%;
                -webkit-box-shadow: 0px -100px 43px -33px #4d97ff inset;
                -moz-box-shadow: 0px -100px 43px -33px #4d97ff inset;
                box-shadow: 0px -100px 43px -33px #4d97ff inset;
                z-index: 2;
            }
        }

        .wrapper__task-expired {
            background-color: #e95454;

            &::before {
                content: "";
                position: absolute;
                bottom: 0;
                left: 0;
                width: 100%;
                height: 70%;
                -webkit-box-shadow: 0px -100px 43px -33px #e95454 inset;
                -moz-box-shadow: 0px -100px 43px -33px #e95454 inset;
                box-shadow: 0px -100px 43px -33px #e95454 inset;
                z-index: 2;
            }
        }

        .tasks-wrapper__task-completed {
            background-color: #1ee6a3;

            &::before {
                content: "";
                position: absolute;
                bottom: 0;
                left: 0;
                width: 100%;
                height: 70%;
                -webkit-box-shadow: 0px -100px 43px -33px #1ee6a3 inset;
                -moz-box-shadow: 0px -100px 43px -33px #1ee6a3 inset;
                box-shadow: 0px -100px 43px -33px #1ee6a3 inset;
                z-index: 2;
            }

            .tasks-wrapper__title {
                text-decoration: line-through;
            }

            .tasks-wrapper__subtasks {
                .tasks-wrapper__subtask {
                    text-decoration: line-through;
                }
            }
        }
    }

    .tasks-wrapper_col {
        display: flex;
        flex-direction: column;
        margin-left: 0;

        .tasks-wrapper__task {
            width: 100%;
            margin-left: 0;
        }
    }
</style>