<template>
    <div class="home">
        <transition name="fade">
            <AddTask v-if="modalAddTask" @closeModalAddTask="toggleModalAddTask"/>
        </transition>
        <transition name="fade">
            <Task
                    v-if="modalTask"
                    :allTasks="tasks"
                    :taskIndex="taskIndex"
                    @closeModalTask="closeModalTask"
                    @removeTask="removeTask"
                    @addFavorites="addFavorites"
                    @removeFavorites="removeFavorites"
                    @saveTasks="saveTasks"
            />
        </transition>

        <div class="home__content container">
            <div class="tasks">
                <Search
                        @voiceAddTask="openVoiceModalAddTask"
                        @searchTasks="searchTasks"
                />
                <TimeBanner/>
                <div class="tasks__row-title-btn">
                    <h2 class="tasks__title" v-if="tasks.length">Задачи</h2>
                    <div
                            class="tasks__toggle-tasks"
                            v-if="tasks.length"
                            :class="{ 'tasks__toggle-tasks_col': column }"
                            @click="columnBlock"
                    ></div>
                </div>

                <h2 class="tasks__empty" v-if="!tasks.length">Здесь пока пусто</h2>
                <Tasks v-if="tasks.length" @openTask="openTask" :allTasks="tasks" :column="column"
                       :searchValue="searchValue"/>
            </div>
            <AddTaskBtn @openModalAddTask="toggleModalAddTask"/>
        </div>
        <Nav/>
    </div>
</template>

<script>
    // @ is an alias to /src
    import Search from "@/components/Search.vue";
    import TimeBanner from "@/components/TimeBanner.vue";
    import Tasks from "@/components/Tasks.vue";
    import Task from "@/components/Task.vue";
    import AddTaskBtn from "@/components/AddTaskBtn.vue";
    import Nav from "@/components/Nav.vue";
    import AddTask from "@/components/AddTask.vue";

    export default {
        name: "Home",
        components: {
            Search,
            TimeBanner,
            Tasks,
            Task,
            AddTaskBtn,
            Nav,
            AddTask,
        },
        data() {
            return {
                modalAddTask: false,
                modalTask: false,
                tasks: [],
                favorites: [],
                taskIndex: Number,
                column: false,
                searchValue: "",
                connection: false,
            };
        },
        computed: {
            allTasks() {
                return this.$store.getters.tasks;
            },
            allFavorites() {
                return this.$store.getters.favorites;
            },
            apiUrl() {
                return this.$store.getters.apiUrl;
            },
            token() {
                return this.$store.getters.token;
            },
        },
        mounted() {
            /*            (async () => {
                            try {
                                const response = await fetch(`${this.apiUrl}/api/task/all`, {
                                    method: 'GET',
                                    headers: {
                                        'Content-Type': 'application/json',
                                        'Authorization': `Bearer ${this.token}`,
                                    },
                                })

                                console.log(response)
                                if (response.ok) {
                                    const data = await response.json();
                                    this.tasks = await data
                                    this.$store.commit("addTasks", tasks);
                                } else {
                                    if (localStorage.getItem("tasks")) {
                                        this.$store.commit("addTasks", JSON.parse(localStorage.getItem("tasks")));
                                    }
                                    if (this.allTasks.length) {
                                        this.tasks = this.allTasks;
                                    }
                                }
                            } catch (e) {
                                if (localStorage.getItem("tasks")) {
                                    this.$store.commit("addTasks", JSON.parse(localStorage.getItem("tasks")));
                                }
                                if (this.allTasks.length) {
                                    this.tasks = this.allTasks;
                                }
                            }

                        })()*/


            if (localStorage.getItem("tasks")) {
                this.$store.commit("addTasks", JSON.parse(localStorage.getItem("tasks")));
            }
            if (this.allTasks.length) {
                this.tasks = this.allTasks;
            }

            if (localStorage.getItem("favorites")) {
                this.$store.commit("addFavorites", JSON.parse(localStorage.getItem("favorites")));
            }
            if (this.allFavorites.length) {
                this.favorites = this.allFavorites;
            }

            if(localStorage.getItem('column') == 'true') {
                this.column = true
            }
        },
        methods: {
            toggleModalAddTask() {
                this.modalAddTask = !this.modalAddTask;
                if (this.allTasks.length) {
                    this.tasks = this.allTasks;
                }
            },
            openVoiceModalAddTask() {
                this.modalAddTask = true;
            },
            openTask(index) {
                this.taskIndex = index;
                this.modalTask = true;
            },
            saveTasks(tasks) {
                localStorage.setItem("tasks", JSON.stringify(tasks));
            },
            closeModalTask() {
                this.modalTask = false;

                /*                const response = await fetch(`${this.apiUrl}/api/task/all`, {
                                    method: 'GET',
                                    headers: {
                                        'Content-Type': 'application/json',
                                        'Authorization': `Bearer ${this.token}`,
                                    },
                                })

                                console.log(response)
                                if (response.ok) {
                                    const data = await response.json();
                                    this.tasks = await data
                                }*/
            },
            addFavorites(index) {
                this.favorites.unshift(this.tasks[index])
                this.$store.commit("addFavorites", this.favorites);
                localStorage.setItem("favorites", JSON.stringify(this.favorites));
            },
            removeFavorites(index) {
                const favoriteIndex = this.allFavorites.findIndex(item => item.idTask == this.tasks[index].idTask)
                this.favorites.splice(favoriteIndex, 1)
                this.$store.commit("addFavorites", this.favorites);
                localStorage.setItem("favorites", JSON.stringify(this.favorites));
            },
            removeTask(index) {


                console.log(this.tasks[index])

                /*                fetch(`${this.apiUrl}/api/Task/delete`, {
                                    method: 'POST',
                                    headers: {
                                        'Content-Type': 'application/json',
                                        'Authorization': `Bearer ${this.token}`
                                    },
                                    body: JSON.stringify({
                                        id: this.tasks[index].id
                                    })
                                })*/

                this.tasks.splice(index, 1);
                this.$store.commit("addTasks", this.tasks);
                localStorage.setItem("tasks", JSON.stringify(this.tasks));

                this.closeModalTask();
            },
            searchTasks(value) {
                this.searchValue = value;
            },
            columnBlock() {
                this.column = !this.column
                localStorage.column = JSON.stringify(this.column);
            }
        },
    };
</script>
